const aadhaar =
    $('Aadhaar JSON').first().json;

const pan =
    $('Pan JSON').first().json;

const dl =
    $('Driving License JSON').first().json;


// =====================================================
// OPTIONAL PASSPORT
// =====================================================

let passport = null;

try {

    passport =
        $('Retrieve Passport').first().json;

} catch (e) {

    passport = null;
}


// =====================================================
// EXTRACT AADHAAR DATA
// =====================================================

const aadhaarData =
    aadhaar.CustomerIdentity.Aadhaar;


// =====================================================
// EXTRACT PAN DATA
// =====================================================

const panData =
    pan.PANCard;


// =====================================================
// EXTRACT DL DATA
// =====================================================

const dlData =
    dl.DrivingLicense;


// =====================================================
// BUILD UNIFIED PROFILE
// =====================================================

const unifiedIdentity = {

    identity: {

        full_name:
            aadhaarData.Name,

        dob:
            aadhaarData.DOB,

        gender:
            aadhaarData.Gender,

        address: {

            street:
                aadhaarData.Address.Street,

            city:
                aadhaarData.Address.City,

            state:
                aadhaarData.Address.State,

            pin:
                aadhaarData.Address.PIN
        },

        aadhaar: {

            aadhaar_number:
                aadhaarData.AadhaarNumber
        },

        pan: {

            pan_number:
                panData.PANNumber,

            category:
                panData.Category
        },

        driving_license: {

            dl_number:
                dlData.DLNumber,

            valid_till:
                dlData.ValidTill
        },

        passport:
            passport || null
    }
};


// =====================================================
// RETURN
// =====================================================

return [
    {
        json: unifiedIdentity
    }
];

const bank =
    $('Retrieve Bank statements').first().json;

const cibil =
    $('Retrieve CIBIL').first().json;

const itr =
    $('Retrieve ITR').first().json;

const wealth =
    $('Retrieve Wealth Data').first().json;

const mf =
    $('Retrieve Mutual Funds').first().json;

const insurance =
    $('Retrieve Insurance').first().json;


// =====================================================
// BUILD FINANCIAL OBJECT
// =====================================================

const financialProfile = {

    financial: {

        bank_statement:
            bank.data,

        cibil:
            cibil.data,

        itr:
            itr.data,

        wealth:
            wealth.data,

        mutual_funds:
            mf.data,

        insurance:
            insurance.data
    }
};


return [
    {
        json: financialProfile
    }
];

// 1. Grab AI Output (Categorization)
const rawAiOutput = $input.first().json.output;
let category = "Mass"; 
try {
    // Clean up markdown formatting if the LLM included it
    const cleanJson = rawAiOutput.replace(/```json/gi, '').replace(/```/g, '').trim();
    const parsed = JSON.parse(cleanJson);
    category = parsed.assigned_category || "Mass";
} catch (e) {
    console.log("AI Parsing failed, defaulting to Mass");
}

// 2. Grab the FULL unified data from the 'Code in JavaScript1' node
// This is the "Fat List" you worked on earlier
const fullCustomerData = $('Code in JavaScript1').first().json; 

// 3. THE SECURITY GUARD (Redacting sensitive numeric IDs for output)
const requiredFields = {
    "identity.aadhaar.aadhaar_number": "Aadhaar Card",
    "identity.pan.pan_number": "PAN Card",
    "financial.bank_statement": "Bank Statements",
    "financial.cibil": "CIBIL Report"
};

function getNestedValue(obj, path) {
    return path.split('.').reduce((acc, part) => acc && acc[part], obj);
}

let missingDocs = [];
for (const [path, docName] of Object.entries(requiredFields)) {
    const val = getNestedValue(fullCustomerData, path);
    // Logic check: if field is missing or empty object
    if (!val || (typeof val === 'object' && Object.keys(val).length === 0)) {
        missingDocs.push(docName);
    }
}

// 4. Dynamic Routing Logic
let nextAgent = "Decision Making Agent";
let taskType = "None";
let logEntry = `Retrieval successful. Category: ${category}.`;

if (missingDocs.length > 0) {
    nextAgent = "Template Agent";
    taskType = "Email";
    logEntry = `Retrieval Halted. Missing: ${missingDocs.join(", ")}.`;
}

// 5. Final Output Construction
return [{
  json: {
    customer_data: fullCustomerData, // This now contains the full merged JSON
    customer_category: category,
    discrepancy_reason: missingDocs.length > 0 ? `Missing: ${missingDocs.join(", ")}` : "",
    log_entry: logEntry,
    task_type: taskType,
    call_agent: nextAgent 
  }
}];

// Ensure the node is set to "Run Once for All Items" in the Settings tab
const allItems = $input.all();
let unifiedProfile = {};

// Helper function to deeply merge and handle mismatched keys
function mergeData(target, source) {
    for (const key in source) {
        if (source[key] instanceof Object && key in target) {
            mergeData(target[key], source[key]);
        } else if (source[key] !== null && source[key] !== undefined) {
            target[key] = source[key];
        }
    }
}

// Loop through the arriving items (Profile, Identity, Bank)
for (const item of allItems) {
    const data = item.json;

    // Normalize mismatched identity keys
    const name = data.customer || data.identity?.full_name || data.full_name;
    if (name) unifiedProfile.customer_name = name;

    // Normalize mismatched occupation keys
    const occupation = data.occupation || data.data?.employment?.occupation;
    if (occupation) unifiedProfile.occupation = occupation;

    // Merge the rest of the financial and identity structures
    mergeData(unifiedProfile, data);
}

// Return one single item with all keys resolved
return { json: unifiedProfile };
